using System.Text.RegularExpressions;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ───────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.StartsWith(result, "(212)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsHyphenSeparator()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesFullPattern()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.Matches(result, new Regex(@"^\(\d{3}\) \d{3}-\d{4}$"));
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsExactFormat()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        Assert.AreEqual("(800) 555-1234", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    [DataRow("")]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException(string digits)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.FormatPhoneNumber(digits));
    }

    // ── BuildGreeting ───────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_DefaultTitle_StartsWithDearMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.StartsWith(result, "Dear Mr.");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_StartsWithDearAndTitle()
    {
        var result = _formatter.BuildGreeting("Jones", "Dr.");

        StringAssert.StartsWith(result, "Dear Dr.");
    }

    [TestMethod]
    public void BuildGreeting_AnyInput_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_ValidName_ContainsName()
    {
        var result = _formatter.BuildGreeting("Anderson");

        StringAssert.Contains(result, "Anderson");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ReturnsExactFormat()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_NullOrWhiteSpace_ThrowsArgumentException(string? name)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.BuildGreeting(name!));
    }

    // ── GenerateSlug ────────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseHyphenated()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_ContainsOnlySlugChars()
    {
        var result = _formatter.GenerateSlug("C# is Great!!!");

        StringAssert.Matches(result, new Regex(@"^[a-z0-9]+(-[a-z0-9]+)*$"));
    }

    [TestMethod]
    public void GenerateSlug_MultiWordTitle_StartsWithFirstWord()
    {
        var result = _formatter.GenerateSlug("Getting Started with .NET");

        StringAssert.StartsWith(result, "getting");
    }

    [TestMethod]
    public void GenerateSlug_MultiWordTitle_EndsWithLastWord()
    {
        var result = _formatter.GenerateSlug("Getting Started with .NET");

        StringAssert.EndsWith(result, "net");
    }

    [TestMethod]
    public void GenerateSlug_DoesNotStartOrEndWithHyphen()
    {
        var result = _formatter.GenerateSlug("---Hello World---");

        StringAssert.DoesNotMatch(result, new Regex(@"^-|-$"));
    }

    [TestMethod]
    public void GenerateSlug_LeadingTrailingSpaces_AreTrimmed()
    {
        var result = _formatter.GenerateSlug("  spaced out  ");

        Assert.AreEqual("spaced-out", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_NullOrWhiteSpace_ThrowsArgumentException(string? title)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.GenerateSlug(title!));
    }

    // ── FormatCurrency ──────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithThatSymbol()
    {
        var result = _formatter.FormatCurrency(9.99m, "€");

        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(42m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_FractionalAmount_EndsWithTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(19.5m);

        StringAssert.EndsWith(result, ".50");
    }

    [TestMethod]
    public void FormatCurrency_MatchesCurrencyPattern()
    {
        var result = _formatter.FormatCurrency(1234.56m, "£");

        StringAssert.Matches(result, new Regex(@"^£\d+\.\d{2}$"));
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinusSign()
    {
        var result = _formatter.FormatCurrency(-5.00m);

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatCurrency_Zero_ReturnsSymbolWithZero()
    {
        var result = _formatter.FormatCurrency(0m);

        Assert.AreEqual("$0.00", result);
    }
}

